member.example:
Bind the AudioSource loop property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceLoopBinder _loop;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _loop;
    }


Bind the AudioSource loop property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceLoopBinder Loop =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _loop;
    }
